/* @diffgazer/ui TUI Theme - Shared base (utility classes, animations, @theme mappings) */

/*
 * Cascade layer order. Declared before any other @layer rule so consumers can
 * predict override resolution without depending on bundler source order.
 * Lower layers in the list lose to higher layers: theme tokens < base styles
 * < component styles < utilities. Tailwind v4 emits its own utilities and
 * components into matching layer names.
 */
@layer theme, base, components, utilities;

.tui-base {
  font-family: var(--tui-font-mono);
  background-color: var(--background);
  color: var(--foreground);
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.scrollbar-thin::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

.scrollbar-thin::-webkit-scrollbar-track {
  background: transparent;
}

.scrollbar-thin::-webkit-scrollbar-thumb {
  background: transparent;
  border-radius: 2px;
  transition: background 0.15s ease;
}

.scrollbar-thin:hover::-webkit-scrollbar-thumb,
.scrollbar-thin:focus-within::-webkit-scrollbar-thumb {
  background: var(--border);
}

.scrollbar-thin::-webkit-scrollbar-thumb:hover {
  background: var(--foreground);
}

.scrollbar-thin {
  scrollbar-width: thin;
  scrollbar-color: transparent transparent;
  transition: scrollbar-color 0.15s ease;
}

.scrollbar-thin:hover,
.scrollbar-thin:focus-within {
  scrollbar-color: var(--border) transparent;
}

@keyframes tui-blink {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0;
  }
}

.cursor-blink {
  animation: tui-blink 1s step-end infinite;
}

@keyframes tui-progress-indeterminate {
  0% {
    width: 40%;
    transform: translateX(-100%);
  }
  50% {
    width: 40%;
    transform: translateX(150%);
  }
  100% {
    width: 40%;
    transform: translateX(-100%);
  }
}

.progress-indeterminate {
  animation: tui-progress-indeterminate 1.5s ease-in-out infinite;
}

@media (prefers-reduced-motion: reduce) {
  .cursor-blink {
    animation: none;
  }
  .progress-indeterminate {
    animation: none;
    width: 40%;
  }
  .scrollbar-thin::-webkit-scrollbar-thumb,
  .scrollbar-thin {
    transition: none;
  }
}

/*
 * scrollbar-gutter: stable on global <html> avoids horizontal layout shift
 * when scrollbars toggle. Safari did not ship scrollbar-gutter until 18.2;
 * @supports keeps Safari 16.4-18.1 from inheriting a declaration it ignores
 * silently. Older Safari simply does not reserve the gutter (cosmetic only).
 */
@supports (scrollbar-gutter: stable) {
  html {
    scrollbar-gutter: stable;
  }
}

@custom-variant dark (&:where(.dark, .dark *, [data-theme="dark"], [data-theme="dark"] *));

@theme {
  --font-sans: "Inter", sans-serif;
  --font-mono: "JetBrains Mono", ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;

  --text-2xs: 0.625rem;
  --text-3xs: 0.5625rem;

  --color-tui-bg: var(--tui-bg);
  --color-tui-fg: var(--tui-fg);
  --color-tui-dim: var(--tui-dim);
  --color-tui-border: var(--tui-border);
  --color-tui-highlight: var(--tui-highlight);
  --color-tui-highlight-fg: var(--tui-highlight-fg);
  --color-tui-input-bg: var(--tui-input-bg);
  --color-tui-muted: var(--tui-muted);
  --color-tui-selection: var(--tui-selection);
  --color-tui-blue: var(--tui-blue);
  --color-tui-violet: var(--tui-violet);
  --color-tui-green: var(--tui-green);
  --color-tui-red: var(--tui-red);
  --color-tui-yellow: var(--tui-yellow);
  --color-tui-surface-1: var(--surface-1);

  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-success: var(--success);
  --color-success-foreground: var(--success-foreground);
  --color-warning: var(--warning);
  --color-warning-foreground: var(--warning-foreground);
  --color-info: var(--info);
  --color-info-foreground: var(--info-foreground);
  --color-error: var(--error);
  --color-error-foreground: var(--error-foreground);
  --color-success-subtle: var(--success-subtle);
  --color-success-fg: var(--success-fg);
  --color-success-border: var(--success-border);
  --color-success-strong: var(--success-strong);
  --color-success-strong-foreground: var(--success-strong-foreground);
  --color-warning-subtle: var(--warning-subtle);
  --color-warning-fg: var(--warning-fg);
  --color-warning-border: var(--warning-border);
  --color-warning-strong: var(--warning-strong);
  --color-warning-strong-foreground: var(--warning-strong-foreground);
  --color-error-subtle: var(--error-subtle);
  --color-error-fg: var(--error-fg);
  --color-error-border: var(--error-border);
  --color-error-strong: var(--error-strong);
  --color-error-strong-foreground: var(--error-strong-foreground);
  --color-info-subtle: var(--info-subtle);
  --color-info-fg: var(--info-fg);
  --color-info-border: var(--info-border);
  --color-info-strong: var(--info-strong);
  --color-info-strong-foreground: var(--info-strong-foreground);
  --color-neutral-subtle: var(--neutral-subtle);
  --color-neutral-border: var(--neutral-border);
  --color-neutral-fg: var(--neutral-fg);
  --color-neutral-strong: var(--neutral-strong);
  --color-neutral-strong-foreground: var(--neutral-strong-foreground);
  --color-action: var(--action);
  --color-action-foreground: var(--action-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);

  --radius-lg: var(--radius);
  --radius-md: calc(var(--radius) - 2px);
  --radius-sm: max(calc(var(--radius) - 4px), 1px);

  /*
   * Z-index scale for overlay surfaces. Native <dialog>.showModal() and the
   * HTML Popover API paint in the browser top-layer, which sits above every
   * z-index value — see apps/docs/content/docs/ui/theme/overview.mdx.
   */
  --z-base: 1;
  --z-dropdown: 100;
  --z-overlay: 200;
  --z-popover: 300;
  --z-toast: 400;

  --animate-fade-in: fade-in 0.2s ease-out;
  --animate-fade-out: fade-out 0.15s ease-in forwards;
  --animate-slide-in: slide-in 0.2s ease-out;
  --animate-slide-out: slide-out 0.15s ease-in forwards;
  --animate-slide-in-right: slide-in-right 0.2s ease-out;
  --animate-slide-out-right: slide-out-right 0.15s ease-in forwards;
  --animate-slide-in-left: slide-in-left 0.2s ease-out;
  --animate-slide-out-left: slide-out-left 0.15s ease-in forwards;
  --animate-slide-in-top: slide-in-top 0.2s ease-out;
  --animate-slide-out-top: slide-out-top 0.15s ease-in forwards;
  --animate-slide-in-bottom: slide-in-bottom 0.2s ease-out;
  --animate-slide-out-bottom: slide-out-bottom 0.15s ease-in forwards;

  /*
   * Floating-surface animation contract (Popover, Select, future Menu/Combobox via FloatingPanel).
   * Each `--ui-content-enter-from-<side>` / `--ui-content-exit-to-<side>` token holds the full
   * `animation` shorthand for that direction, so `.ui-floating-panel[data-side="<side>"]` maps
   * directly. All 8 directional tokens are kept (vs. collapsed to a single pair) so consumers
   * can override per side with transform-based keyframes; `--ui-content-transform-origin` is
   * set automatically by FloatingPanel for those overrides. Reduced motion overrides below.
   */
  --ui-content-enter-duration: 60ms;
  --ui-content-exit-duration: 40ms;
  --ui-content-enter-from-top: ui-content-enter-fade var(--ui-content-enter-duration) linear;
  --ui-content-enter-from-bottom: ui-content-enter-fade var(--ui-content-enter-duration) linear;
  --ui-content-enter-from-left: ui-content-enter-fade var(--ui-content-enter-duration) linear;
  --ui-content-enter-from-right: ui-content-enter-fade var(--ui-content-enter-duration) linear;
  --ui-content-exit-to-top: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
  --ui-content-exit-to-bottom: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
  --ui-content-exit-to-left: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
  --ui-content-exit-to-right: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;

  @keyframes fade-in {
    from {
      opacity: 0;
    }
    to {
      opacity: 1;
    }
  }
  @keyframes fade-out {
    from {
      opacity: 1;
    }
    to {
      opacity: 0;
    }
  }
  @keyframes slide-in {
    from {
      transform: translateY(10px);
      opacity: 0;
    }
    to {
      transform: translateY(0);
      opacity: 1;
    }
  }
  @keyframes slide-out {
    from {
      transform: translateY(0);
      opacity: 1;
    }
    to {
      transform: translateY(8px);
      opacity: 0;
    }
  }
  @keyframes slide-in-right {
    from {
      transform: translateX(100%);
      opacity: 0;
    }
    to {
      transform: translateX(0);
      opacity: 1;
    }
  }
  @keyframes slide-out-right {
    from {
      transform: translateX(0);
      opacity: 1;
    }
    to {
      transform: translateX(100%);
      opacity: 0;
    }
  }
  @keyframes slide-in-left {
    from {
      transform: translateX(-100%);
      opacity: 0;
    }
    to {
      transform: translateX(0);
      opacity: 1;
    }
  }
  @keyframes slide-out-left {
    from {
      transform: translateX(0);
      opacity: 1;
    }
    to {
      transform: translateX(-100%);
      opacity: 0;
    }
  }
  @keyframes slide-in-top {
    from {
      transform: translateY(-100%);
      opacity: 0;
    }
    to {
      transform: translateY(0);
      opacity: 1;
    }
  }
  @keyframes slide-out-top {
    from {
      transform: translateY(0);
      opacity: 1;
    }
    to {
      transform: translateY(-100%);
      opacity: 0;
    }
  }
  @keyframes slide-in-bottom {
    from {
      transform: translateY(100%);
      opacity: 0;
    }
    to {
      transform: translateY(0);
      opacity: 1;
    }
  }
  @keyframes slide-out-bottom {
    from {
      transform: translateY(0);
      opacity: 1;
    }
    to {
      transform: translateY(100%);
      opacity: 0;
    }
  }

}

/*
 * Floating-surface keyframes. Tailwind v4 keeps @keyframes nested in @theme only
 * when their paired `--animate-*` variable is used; these are paired with
 * `--ui-content-*` (not `--animate-*`), so they're declared at top level to
 * ensure emission.
 */
@keyframes ui-content-enter-fade {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}
@keyframes ui-content-exit-fade {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

/*
 * Public CSS variables for consumers to override per-instance:
 *   --ui-floating-z         — z-index layer (default: var(--z-popover))
 *   --ui-content-enter-from-{top|bottom|left|right}   — enter animation shorthand
 *   --ui-content-exit-to-{top|bottom|left|right}      — exit animation shorthand
 *   --ui-content-enter-duration, --ui-content-exit-duration
 *   --ui-content-transform-origin  — set automatically; usable from transform-based overrides
 *   --ui-floating-trigger-width    — set when matchTriggerWidth (Select etc.)
 *
 * Rules live in @layer components so consumer @layer utilities (e.g. animate-none)
 * can override them without specificity escalation. The `[data-positioned]` gate
 * prevents the first-frame race where the animation would otherwise start before
 * `useFloatingPosition` has measured.
 */
@layer components {
  .ui-floating-panel {
    transform-origin: var(--ui-content-transform-origin, center);
    z-index: var(--ui-floating-z, var(--z-popover));
  }
  .ui-floating-panel[data-state="open"][data-positioned][data-side="bottom"] {
    animation: var(--ui-content-enter-from-top);
  }
  .ui-floating-panel[data-state="open"][data-positioned][data-side="top"] {
    animation: var(--ui-content-enter-from-bottom);
  }
  .ui-floating-panel[data-state="open"][data-positioned][data-side="right"] {
    animation: var(--ui-content-enter-from-left);
  }
  .ui-floating-panel[data-state="open"][data-positioned][data-side="left"] {
    animation: var(--ui-content-enter-from-right);
  }
  .ui-floating-panel[data-state="closed"] {
    pointer-events: none;
  }
  .ui-floating-panel[data-state="closed"][data-side="bottom"] {
    animation: var(--ui-content-exit-to-top);
  }
  .ui-floating-panel[data-state="closed"][data-side="top"] {
    animation: var(--ui-content-exit-to-bottom);
  }
  .ui-floating-panel[data-state="closed"][data-side="right"] {
    animation: var(--ui-content-exit-to-left);
  }
  .ui-floating-panel[data-state="closed"][data-side="left"] {
    animation: var(--ui-content-exit-to-right);
  }
}

/*
 * Tailwind v4 compiles `animate-<key>` to `animation: var(--animate-<key>)`.
 * Overriding each animation token to `none` under prefers-reduced-motion
 * neutralizes every token consumer (Popover, Select, Toast, future surfaces)
 * without retrofitting `motion-safe:` everywhere. Components that use the
 * arbitrary `animate-[...]` form or CSS-only animations handle reduced motion
 * locally.
 */
@media (prefers-reduced-motion: reduce) {
  :root {
    --animate-fade-in: none;
    --animate-fade-out: none;
    --animate-slide-in: none;
    --animate-slide-out: none;
    --animate-slide-in-right: none;
    --animate-slide-out-right: none;
    --animate-slide-in-left: none;
    --animate-slide-out-left: none;
    --animate-slide-in-top: none;
    --animate-slide-out-top: none;
    --animate-slide-in-bottom: none;
    --animate-slide-out-bottom: none;
    --ui-content-enter-from-top: ui-content-enter-fade var(--ui-content-enter-duration) linear;
    --ui-content-enter-from-bottom: ui-content-enter-fade var(--ui-content-enter-duration) linear;
    --ui-content-enter-from-left: ui-content-enter-fade var(--ui-content-enter-duration) linear;
    --ui-content-enter-from-right: ui-content-enter-fade var(--ui-content-enter-duration) linear;
    --ui-content-exit-to-top: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
    --ui-content-exit-to-bottom: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
    --ui-content-exit-to-left: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
    --ui-content-exit-to-right: ui-content-exit-fade var(--ui-content-exit-duration) linear forwards;
  }
}

/* Windows High Contrast Mode */
@media (forced-colors: active) {
  :root {
    --border: CanvasText;
    --ring: Highlight;
    --foreground: CanvasText;
    --background: Canvas;
    --muted-foreground: CanvasText;
  }
}

/* Increased contrast preference */
@media (prefers-contrast: more) {
  :root,
  [data-theme="dark"] {
    --tui-dim: #b3b3b3;
    --tui-border: #777777;
    --tui-muted: #999999;
  }
  [data-theme="light"] {
    --tui-dim: #4a4a4a;
    --tui-border: #6e6e6e;
    --tui-muted: #555555;
  }
}

/* Shiki dual-theme variable resolution */
.shiki,
.shiki span {
  color: var(--shiki-light);
  background-color: var(--shiki-light-bg);
}

[data-theme="light"] .shiki,
[data-theme="light"] .shiki span {
  color: var(--shiki-light);
  background-color: var(--shiki-light-bg);
}

[data-theme="dark"] .shiki,
[data-theme="dark"] .shiki span {
  color: var(--shiki-dark);
  background-color: var(--shiki-dark-bg);
}

/* @diffgazer/ui TUI Theme - Diffgazer (Minimal Monochrome) */

@import "./theme-base.css";

:root,
[data-theme="dark"] {
  /* Primitive TUI Colors - Diffgazer Theme */
  --tui-bg: #0a0a0a;
  --tui-fg: #e5e5e5;
  --tui-dim: #9c9c9c;
  --tui-border: #606060;
  --tui-highlight: #ffffff;
  --tui-highlight-fg: #000000;
  --tui-input-bg: #0a0a0a;
  --tui-muted: #787878;
  --tui-selection: #333333;

  /* Accent colors - simplified for minimal theme */
  --tui-blue: #ccccff;  /* light for links */
  --tui-violet: #787878;
  --tui-green: #e5e5e5; /* white for success in minimal */
  --tui-red: #ff7b72;   /* keep for error */
  --tui-yellow: #d29922; /* keep for warning */

  /* Code syntax palette (shared by Fumadocs + generated snippets) */
  --code-comment: var(--tui-dim);
  --code-string: var(--tui-violet);
  --code-number: var(--tui-violet);
  --code-keyword: var(--tui-blue);
  --code-function: var(--tui-green);
  --code-tag: var(--tui-green);
  --code-attr: var(--tui-blue);
  --code-parameter: var(--tui-yellow);
  --code-operator: var(--tui-red);
  --code-variable: var(--tui-fg);
  --code-type: var(--tui-blue);

  --tui-font-mono: "JetBrains Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas,
    "Liberation Mono", monospace;

  /* Semantic mappings */
  --background: var(--tui-bg);
  --foreground: var(--tui-fg);
  --primary: var(--tui-fg);
  --primary-foreground: var(--tui-bg);
  --secondary: var(--tui-selection);
  --secondary-foreground: var(--tui-fg);
  --muted: var(--tui-muted);
  --muted-foreground: var(--tui-dim);
  --border: var(--tui-border);
  --input: var(--tui-selection);
  --destructive: var(--tui-red);
  --destructive-foreground: var(--tui-bg);
  --accent: var(--tui-highlight);
  --accent-foreground: var(--tui-highlight-fg);
  --card: var(--tui-selection);
  --card-foreground: var(--tui-fg);
  --popover: var(--tui-selection);
  --popover-foreground: var(--tui-fg);
  --ring: var(--tui-fg);
  --success: var(--tui-green);
  --success-foreground: var(--tui-bg);
  --warning: var(--tui-yellow);
  --warning-foreground: var(--tui-bg);
  --info: var(--tui-blue);
  --info-foreground: var(--tui-bg);
  --error: var(--tui-red);
  --error-foreground: var(--tui-bg);

  --success-subtle: #e5e5e51a;
  --success-fg: var(--tui-green);
  --success-border: var(--tui-green);
  --success-strong: var(--tui-green);
  --success-strong-foreground: var(--tui-bg);

  --warning-subtle: #d299220d;
  --warning-fg: var(--tui-yellow);
  --warning-border: var(--tui-yellow);
  --warning-strong: var(--tui-yellow);
  --warning-strong-foreground: var(--tui-bg);

  --error-subtle: #ff7b721a;
  --error-fg: var(--tui-red);
  --error-border: var(--tui-red);
  --error-strong: var(--tui-red);
  --error-strong-foreground: var(--tui-bg);

  --info-subtle: #ccccff1a;
  --info-fg: var(--tui-blue);
  --info-border: var(--tui-blue);
  --info-strong: var(--tui-blue);
  --info-strong-foreground: var(--tui-bg);

  --neutral-subtle: #6666661a;
  --neutral-border: var(--tui-border);
  --neutral-fg: var(--tui-muted);
  --neutral-strong: var(--tui-muted);
  --neutral-strong-foreground: var(--tui-bg);

  --action: var(--tui-highlight);
  --action-foreground: var(--tui-highlight-fg);

  /* Surface elevation steps. --surface-1 is one step lighter than --tui-bg
     for Linear/Raycast-style elevated panels (Panel frame="surface"). */
  --surface-1: #111111;

  --trans-fast: 0.15s ease;
  --radius: 0.25rem;
}

/* Light theme — available for package consumers via data-theme="light" */
[data-theme="light"] {
  /* Primitive TUI Colors - Diffgazer Light Theme */
  --tui-bg: #f7f8f5;
  --tui-fg: #1f2328;
  --tui-dim: #5f6872;
  --tui-border: #aeb7c0;
  --tui-highlight: #1f2328;
  --tui-highlight-fg: #ffffff;
  --tui-input-bg: #ffffff;
  --tui-muted: #69717a;
  --tui-selection: #e8edf3;

  /* Accent colors */
  --tui-blue: #0b63ce;
  --tui-violet: #6f42c1;
  --tui-green: #0f7a4f;
  --tui-red: #c62828;
  --tui-yellow: #8a5a00;

  /* Code syntax palette (shared by Fumadocs + generated snippets) */
  --code-comment: var(--tui-dim);
  --code-string: var(--tui-violet);
  --code-number: var(--tui-violet);
  --code-keyword: var(--tui-blue);
  --code-function: var(--tui-green);
  --code-tag: var(--tui-green);
  --code-attr: var(--tui-blue);
  --code-parameter: var(--tui-yellow);
  --code-operator: var(--tui-red);
  --code-variable: var(--tui-fg);
  --code-type: var(--tui-blue);

  /* Semantic mappings */
  --background: var(--tui-bg);
  --foreground: var(--tui-fg);
  --primary: var(--tui-highlight);
  --primary-foreground: var(--tui-highlight-fg);
  --secondary: var(--tui-selection);
  --secondary-foreground: var(--tui-fg);
  --muted: var(--tui-muted);
  --muted-foreground: var(--tui-dim);
  --border: var(--tui-border);
  --input: var(--tui-input-bg);
  --destructive: var(--tui-red);
  --destructive-foreground: #ffffff;
